/* ================================================================
   ToyForge Studio — main.min.js  (mobile-first rewrite)
   ================================================================ */

const lerp = (a, b, t) => a + (b - a) * t;
function easeOut(t) { return 1 - Math.pow(1 - t, 3); }

/* ── Lenis smooth scroll ── */
let lenis;
window.addEventListener('DOMContentLoaded', () => {
  if (window.Lenis) {
    lenis = new Lenis({ lerp: 0.085, smoothWheel: true });
    function raf(time) { lenis.raf(time); requestAnimationFrame(raf); }
    requestAnimationFrame(raf);
  }
});

/* ── Cursor glow (desktop hover only) ── */
const cg = document.getElementById('cursor-glow');
if (window.matchMedia('(hover:hover)').matches && cg) {
  document.addEventListener('mousemove', e => {
    cg.style.left = e.clientX + 'px';
    cg.style.top  = e.clientY + 'px';
  });
}

/* ── Scrolled nav ── */
const mainNav = document.getElementById('mainNav');
window.addEventListener('scroll', () =>
  mainNav && mainNav.classList.toggle('scrolled', window.scrollY > 60));

/* ── Hamburger ── */
const hamburger = document.getElementById('hamburger');
const mobileMenu = document.getElementById('mobileMenu');
if (hamburger && mobileMenu) {
  hamburger.addEventListener('click', () => mobileMenu.classList.toggle('open'));
  mobileMenu.querySelectorAll('a').forEach(a =>
    a.addEventListener('click', () => mobileMenu.classList.remove('open')));
}

/* ── Marquee ── */
const marqItems = [
  'FSC-Certified Wood','6 Shape Families','Montessori Aligned',
  'EN71 Certified','STEM-Focused','Award-Winning Design',
  'Non-Toxic Paints','28 Countries','140K Families',
  'Carbon Neutral 2023','Lifetime Guarantee','Safety First'
];
const track = document.getElementById('marqueeTrack');
if (track) {
  [...marqItems, ...marqItems].forEach(txt => {
    const d = document.createElement('div');
    d.className = 'marquee-item';
    d.innerHTML = `<span class="marquee-dot"></span>${txt}`;
    track.appendChild(d);
  });
}

/* ── Intersection reveal ── */
const revealEls = document.querySelectorAll('.reveal,.reveal-l,.reveal-r');
const revObs = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('in'); });
}, { threshold: 0.12, rootMargin: '0px 0px -60px 0px' });
revealEls.forEach(el => revObs.observe(el));

/* ── Lazy video loader ── */
const lazyVidObs = new IntersectionObserver(entries => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      const v = entry.target;
      if (v.dataset.src && !v.src) {
        v.src = v.dataset.src;
        v.play().catch(() => {});
      }
      lazyVidObs.unobserve(v);
    }
  });
}, { rootMargin: '200px' });
document.querySelectorAll('.lazy-video').forEach(v => lazyVidObs.observe(v));

/* ================================================================
   GSAP animations (runs after GSAP + ScrollTrigger are loaded)
   ================================================================ */
function initGSAP() {
  if (!window.gsap || !window.ScrollTrigger) return;
  gsap.registerPlugin(ScrollTrigger);
  if (lenis) ScrollTrigger.refresh();

  gsap.from('.hero-eyebrow', { opacity:0, y:30, duration:1, ease:'power3.out', delay:.3 });
  gsap.from('.hero-title .line1', { opacity:0, y:40, duration:1, ease:'power3.out', delay:.5 });
  gsap.from('.hero-title .line2', { opacity:0, y:40, duration:1, ease:'power3.out', delay:.7 });
  gsap.from('.hero-sub',  { opacity:0, y:30, duration:1, ease:'power3.out', delay:.85 });
  gsap.from('.hero-btns', { opacity:0, y:20, duration:1, ease:'power3.out', delay:1 });
  gsap.from('.scroll-cue', { opacity:0, duration:1, delay:1.4 });

  /* Counter animation for stats */
  document.querySelectorAll('.stat-n').forEach(el => {
    const raw = el.textContent;
    const suffix = raw.replace(/[0-9.]/g, '');
    const val = parseFloat(raw);
    if (!isNaN(val)) {
      ScrollTrigger.create({
        trigger: el, start: 'top 80%',
        onEnter: () => {
          gsap.fromTo({ v: 0 }, { v: val }, {
            duration: 1.8, ease: 'power2.out',
            onUpdate() { el.textContent = Math.round(this.targets()[0].v).toLocaleString() + suffix; }
          });
        }
      });
    }
  });

  /* Feat cards */
  gsap.from('.feat-card', {
    y:50, opacity:0, stagger:.12, duration:.9, ease:'power2.out',
    scrollTrigger: { trigger: '.feat-grid', start: 'top 75%' }
  });
}

/* ================================================================
   THREE.JS  — waits until THREE is loaded
   ================================================================ */
function waitForThree(cb) {
  if (window.THREE) { cb(); return; }
  const t = setInterval(() => { if (window.THREE) { clearInterval(t); cb(); } }, 80);
}

/* ── Helper: add drag (mouse + touch) to rotate a Three.js Group ── */
function makeDraggable(canvas, onDrag) {
  let down = false, prevX = 0, prevY = 0, velX = 0, velY = 0;
  const start = (x, y) => { down = true; prevX = x; prevY = y; velX = velY = 0; };
  const move  = (x, y) => {
    if (!down) return;
    velX = 0.009 * (x - prevX);
    velY = 0.009 * (y - prevY);
    onDrag(velX, velY);
    prevX = x; prevY = y;
  };
  const end   = () => { down = false; };
  canvas.addEventListener('mousedown',  e => start(e.clientX, e.clientY));
  canvas.addEventListener('touchstart', e => { start(e.touches[0].clientX, e.touches[0].clientY); e.preventDefault(); }, { passive: false });
  window.addEventListener('mousemove',  e => move(e.clientX, e.clientY));
  window.addEventListener('touchmove',  e => { if (down) move(e.touches[0].clientX, e.touches[0].clientY); }, { passive: true });
  window.addEventListener('mouseup',    end);
  window.addEventListener('touchend',   end);
  return () => ({ down, velX, velY });
}

/* ── Pause renderer when off-screen ── */
function pauseWhenHidden(canvas, startFn) {
  let handle = null;
  const obs = new IntersectionObserver(entries => {
    entries.forEach(en => {
      if (en.isIntersecting) { if (handle === null) handle = requestAnimationFrame(startFn(h => handle = h)); }
      else { if (handle !== null) { cancelAnimationFrame(handle); handle = null; } }
    });
  }, { threshold: 0 });
  obs.observe(canvas);
  handle = requestAnimationFrame(startFn(h => handle = h));
}

/* ================================================================
   HERO CANVAS
   ================================================================ */
function initHeroCanvas() {
  const el = document.getElementById('hero-canvas');
  if (!el) return;
  let W = window.innerWidth, H = window.innerHeight;
  const renderer = new THREE.WebGLRenderer({ canvas: el, antialias: true, alpha: true });
  renderer.setSize(W, H); renderer.setPixelRatio(Math.min(devicePixelRatio, 1.5));
  renderer.setClearColor(0, 0);
  const scene = new THREE.Scene(), cam = new THREE.PerspectiveCamera(60, W / H, .1, 200);
  cam.position.z = 22;
  const COLORS = [0xFF5A2C,0xFFD025,0x00C49A,0x8B6FE8,0xF53FA5,0x2BB8FF];
  const GEOS   = [
    new THREE.BoxGeometry(.5,.5,.5), new THREE.OctahedronGeometry(.42),
    new THREE.TetrahedronGeometry(.46), new THREE.CylinderGeometry(0,.4,.75,5),
    new THREE.TorusGeometry(.36,.1,8,24), new THREE.CylinderGeometry(.38,.38,.2,6),
    new THREE.SphereGeometry(.3,12,12)
  ];
  const COUNT = W < 600 ? 14 : 26;
  const meshes = [];
  for (let i = 0; i < COUNT; i++) {
    const m = new THREE.Mesh(GEOS[i % GEOS.length],
      new THREE.MeshPhongMaterial({ color: COLORS[i%6], opacity: .18+.22*Math.random(), transparent: true, shininess: 80 }));
    m.position.set(48*(Math.random()-.5), 28*(Math.random()-.5), 12*(Math.random()-.5)-6);
    m.userData = { rx:.022*(Math.random()-.5), ry:.018*(Math.random()-.5),
                   oy: m.position.y, fs:.4+.6*Math.random(), fo: Math.random()*Math.PI*2 };
    scene.add(m); meshes.push(m);
  }
  scene.add(new THREE.AmbientLight(0xffffff, .5));
  const pL1 = new THREE.PointLight(0xFF5A2C, 4, 50); pL1.position.set(0,8,10); scene.add(pL1);
  scene.add(Object.assign(new THREE.PointLight(0x8B6FE8,3,40), { position: new THREE.Vector3(-14,-6,6) }));
  scene.add(Object.assign(new THREE.PointLight(0xFFD025,2.5,35), { position: new THREE.Vector3(14,6,4) }));
  let t = 0;
  function loop(setH) {
    const h = requestAnimationFrame(() => loop(setH));
    setH(h); t += .012;
    meshes.forEach(m => {
      m.rotation.x += m.userData.rx; m.rotation.y += m.userData.ry;
      m.position.y = m.userData.oy + .7*Math.sin(t*m.userData.fs + m.userData.fo);
    });
    pL1.position.x = 10*Math.cos(.6*t); pL1.position.y = 7*Math.sin(.4*t);
    renderer.render(scene, cam);
  }
  pauseWhenHidden(el, loop);
  window.addEventListener('resize', () => {
    W = window.innerWidth; H = window.innerHeight;
    renderer.setSize(W,H); cam.aspect = W/H; cam.updateProjectionMatrix();
  });
}

/* ================================================================
   TOY 1  — Shape Sorter
   ================================================================ */
function initToy1() {
  const el = document.getElementById('toy1-canvas');
  if (!el) return;
  const par = el.parentElement;
  let W = par.clientWidth, H = par.clientHeight || W;
  const renderer = new THREE.WebGLRenderer({ canvas: el, antialias: true, alpha: true });
  renderer.setSize(W,H); renderer.setPixelRatio(Math.min(devicePixelRatio,1.5));
  renderer.setClearColor(0,0); renderer.shadowMap.enabled = true;
  const scene = new THREE.Scene(), cam = new THREE.PerspectiveCamera(48, W/H, .1, 100);
  cam.position.set(0,2,10);
  scene.add(new THREE.AmbientLight(0xffffff,.6));
  const pL = new THREE.PointLight(0xffffff,5,40); pL.position.set(5,8,8); pL.castShadow=true; scene.add(pL);
  scene.add(Object.assign(new THREE.PointLight(0xFF5A2C,2.5,30), { position: new THREE.Vector3(-5,-3,5) }));
  scene.add(Object.assign(new THREE.PointLight(0xFFD025,2,25),   { position: new THREE.Vector3(3,6,-4) }));
  const group = new THREE.Group(); scene.add(group);
  const base = new THREE.Mesh(new THREE.BoxGeometry(4.8,.28,2.2),
    new THREE.MeshPhongMaterial({ color:0xE8C87A, shininess:60 }));
  base.position.y=-1.7; base.castShadow=true; group.add(base);
  const baseTop = new THREE.Mesh(new THREE.BoxGeometry(4.9,.08,2.3),
    new THREE.MeshPhongMaterial({ color:0xD4A855, shininess:80 }));
  baseTop.position.y=-1.57; group.add(baseTop);
  const PEGS = [
    {x:-2.2,color:0xFF5A2C,seg:6},{x:-1.1,color:0xFFD025,seg:32},
    {x:0,color:0x00C49A,seg:3},{x:1.1,color:0x2BB8FF,seg:4},
    {x:2.2,color:0x8B6FE8,seg:4,rot:Math.PI/4}
  ];
  PEGS.forEach(p => {
    const peg = new THREE.Mesh(new THREE.CylinderGeometry(.1,.1,2.2,12),
      new THREE.MeshPhongMaterial({ color:0xE8E0C0, shininess:90 }));
    peg.position.set(p.x,-.1,0); group.add(peg);
    const disc = new THREE.Mesh(new THREE.CylinderGeometry(.65,.65,.15,p.seg),
      new THREE.MeshPhongMaterial({ color:p.color, shininess:80 }));
    disc.position.set(p.x,-1.58,0); if(p.rot) disc.rotation.y=p.rot;
    disc.castShadow=true; group.add(disc);
    for (let n=0; n<3; n++) {
      const rad = .58-.09*n;
      const geo = p.seg===3 ? new THREE.CylinderGeometry(0,rad,.32,3)
                : p.seg===4 ? new THREE.BoxGeometry(1.6*rad,.27,1.6*rad)
                :             new THREE.CylinderGeometry(rad,rad,.27,p.seg);
      const col = new THREE.Color(p.color); col.offsetHSL(0,0,.06*n-.05);
      const piece = new THREE.Mesh(geo, new THREE.MeshPhongMaterial({ color:col, shininess:100 }));
      piece.position.set(p.x,.42*n-1.24,0);
      if(p.rot) piece.rotation.y=p.rot; piece.castShadow=true; group.add(piece);
    }
  });
  let rotX=.3, rotY=.4, velX=0, velY=0;
  makeDraggable(el, (dx, dy) => { velY+=dx; velX+=dy; });
  let t=0;
  function loop(setH) {
    const h = requestAnimationFrame(() => loop(setH)); setH(h); t+=.014;
    rotY+=velY; rotX+=velX;
    rotX = Math.max(-.6, Math.min(.8, rotX));
    velX*=.92; velY*=.92;
    group.rotation.x=rotX; group.rotation.y=rotY;
    group.position.y=.15*Math.sin(.5*t);
    pL.intensity=4.5+.5*Math.sin(.7*t);
    renderer.render(scene,cam);
  }
  pauseWhenHidden(el, loop);
  window.addEventListener('resize', () => {
    W=par.clientWidth; H=par.clientHeight||W;
    renderer.setSize(W,H); cam.aspect=W/H; cam.updateProjectionMatrix();
  });
}

/* ================================================================
   TOY 2  — Color Slide (bead rail puzzle)
   ================================================================ */
function initToy2() {
  const el = document.getElementById('toy2-canvas');
  if (!el) return;
  const par = el.parentElement;
  let W = par.clientWidth, H = par.clientHeight || W;
  const renderer = new THREE.WebGLRenderer({ canvas:el, antialias:true, alpha:true });
  renderer.setSize(W,H); renderer.setPixelRatio(Math.min(devicePixelRatio,1.5));
  renderer.setClearColor(0,0); renderer.shadowMap.enabled=true;
  const scene = new THREE.Scene(), cam = new THREE.PerspectiveCamera(48,W/H,.1,100);
  cam.position.set(0,1.5,11);
  scene.add(new THREE.AmbientLight(0xffffff,.55));
  const pL = new THREE.PointLight(0xffffff,5.5,45); pL.position.set(5,8,8); pL.castShadow=true; scene.add(pL);
  scene.add(Object.assign(new THREE.PointLight(0x8B6FE8,3,30), { position: new THREE.Vector3(-6,-3,5) }));
  scene.add(Object.assign(new THREE.PointLight(0xF53FA5,2,22), { position: new THREE.Vector3(4,6,-4) }));
  const group = new THREE.Group(); scene.add(group);
  const frameMat = new THREE.MeshPhongMaterial({ color:0xFFD025, shininess:80 });
  [[4,.22,.32,0,2,0],[4,.22,.32,0,-2,0],[.22,4.22,.32,-2,0,0],[.22,4.22,.32,2,0,0]].forEach(([w,h,d,x,y,z]) => {
    const m = new THREE.Mesh(new THREE.BoxGeometry(w,h,d), frameMat);
    m.position.set(x,y,z); m.castShadow=true; group.add(m);
  });
  const RAIL_COLORS = [[0xFF5A2C,0xFF8235],[0x00C49A,0x33D9B2],[0x2BB8FF,0x66CDFF],[0x8B6FE8,0xA98CF8]];
  const beads = [];
  for (let r=0; r<4; r++) {
    const rx = 1.1*(r-1.5);
    const rail = new THREE.Mesh(new THREE.CylinderGeometry(.055,.055,3.6,10),
      new THREE.MeshPhongMaterial({ color:0xD4A855, shininess:60 }));
    rail.position.set(rx,0,0); group.add(rail);
    for (let b=0; b<3; b++) {
      const bead = new THREE.Mesh(new THREE.CylinderGeometry(.42,.42,.32,28),
        new THREE.MeshPhongMaterial({ color:RAIL_COLORS[r][b%2], shininess:110 }));
      const baseY = .9*b-1.3;
      bead.position.set(rx, baseY, 0); bead.castShadow=true; group.add(bead);
      beads.push({ mesh:bead, baseY, phase:.8*r+.6*b, speed:.6+.35*Math.random(), amp:.3+.2*Math.random() });
    }
  }
  let rotX=.2, rotY=.3, velX=0, velY=0;
  makeDraggable(el, (dx,dy) => { velY+=dx; velX+=dy; });
  let t=0;
  function loop(setH) {
    const h=requestAnimationFrame(()=>loop(setH)); setH(h); t+=.014;
    rotY+=velY; rotX+=velX;
    rotX=Math.max(-.55,Math.min(.7,rotX)); velX*=.92; velY*=.92;
    group.rotation.x=rotX; group.rotation.y=rotY;
    group.position.y=.12*Math.sin(.5*t);
    beads.forEach(b=>{ b.mesh.position.y=b.baseY+Math.sin(t*b.speed+b.phase)*b.amp; });
    pL.intensity=5+.6*Math.sin(.7*t);
    renderer.render(scene,cam);
  }
  pauseWhenHidden(el, loop);
  window.addEventListener('resize',()=>{
    W=par.clientWidth; H=par.clientHeight||W;
    renderer.setSize(W,H); cam.aspect=W/H; cam.updateProjectionMatrix();
  });
}

/* ================================================================
   SHOWCASE  — scroll-driven 3-D assembly
   ================================================================ */
function initShowcase() {
  const sec = document.getElementById('showcase');
  const el  = document.getElementById('showcase-canvas');
  if (!el || !sec) return;
  let W = window.innerWidth, H = window.innerHeight;
  const renderer = new THREE.WebGLRenderer({ canvas:el, antialias:true, alpha:true });
  renderer.setSize(W,H); renderer.setPixelRatio(Math.min(devicePixelRatio,1.5));
  renderer.setClearColor(0x181824,1); renderer.shadowMap.enabled=true;
  const scene = new THREE.Scene(), cam = new THREE.PerspectiveCamera(50,W/H,.1,100);
  cam.position.set(0,1,14);
  scene.add(new THREE.AmbientLight(0xffffff,.4));
  const pL1=new THREE.PointLight(0xffffff,5.5,50); pL1.position.set(6,10,10); pL1.castShadow=true; scene.add(pL1);
  const pL2=new THREE.PointLight(0xFFD025,3,35); pL2.position.set(-8,-4,6); scene.add(pL2);
  const pL3=new THREE.PointLight(0xFF5A2C,2.5,30); pL3.position.set(4,8,-6); scene.add(pL3);
  const group = new THREE.Group(); scene.add(group);
  const base = new THREE.Mesh(new THREE.BoxGeometry(6,.32,2.6),
    new THREE.MeshPhongMaterial({color:0xE8C87A,shininess:70}));
  base.userData={aY:-2,sY:14}; base.position.y=14; base.castShadow=true; group.add(base);
  const baseTop = new THREE.Mesh(new THREE.BoxGeometry(6.1,.1,2.7),
    new THREE.MeshPhongMaterial({color:0xD4A855,shininess:90}));
  baseTop.userData={aY:-1.72,sY:14.3}; baseTop.position.y=14.3; group.add(baseTop);
  const PEGS2=[
    {x:-2.5,color:0xFF5A2C,seg:6},{x:-1.25,color:0xFFD025,seg:32},
    {x:0,color:0x00C49A,seg:3},{x:1.25,color:0x2BB8FF,seg:4},
    {x:2.5,color:0x8B6FE8,seg:4,rot:Math.PI/4}
  ];
  const allParts=[];
  PEGS2.forEach((p,i)=>{
    const peg=new THREE.Mesh(new THREE.CylinderGeometry(.1,.1,2.4,12),
      new THREE.MeshPhongMaterial({color:0xE8E0C0,shininess:90}));
    peg.position.set(p.x,-.5,0); peg.userData={aY:-.5,sY:9+.5*i,delay:.14*i}; group.add(peg); allParts.push(peg);
    const disc=new THREE.Mesh(new THREE.CylinderGeometry(.68,.68,.16,p.seg),
      new THREE.MeshPhongMaterial({color:p.color,shininess:80}));
    disc.position.set(p.x,-1.72,0); if(p.rot)disc.rotation.y=p.rot;
    disc.userData={aY:-1.72,sY:9+.5*i,delay:.14*i}; group.add(disc); allParts.push(disc);
    for(let n=0;n<3;n++){
      const rad=.62-.1*n;
      const geo=p.seg===3?new THREE.CylinderGeometry(0,rad,.3,3)
               :p.seg===4?new THREE.BoxGeometry(1.65*rad,.28,1.65*rad)
               :           new THREE.CylinderGeometry(rad,rad,.28,p.seg);
      const col=new THREE.Color(p.color); col.offsetHSL(0,0,.07*n-.06);
      const piece=new THREE.Mesh(geo,new THREE.MeshPhongMaterial({color:col,shininess:100}));
      const bY=.43*n-1.3; piece.position.set(p.x,bY+14,0);
      if(p.rot)piece.rotation.y=p.rot;
      piece.userData={aY:bY,sY:bY+14,delay:.07*(3*i+n)}; group.add(piece); allParts.push(piece);
    }
  });
  const STEPS=[
    {eye:'The Foundation',title:'Precision-Milled Board',     desc:'Each sorting board is CNC-milled from sustainably sourced hardwood to ±0.1mm tolerances.'},
    {eye:'The Pegs',      title:'Colour-Coded Posts',          desc:'Smooth steel pegs with rubber-tipped caps guide little fingers to the right slot every time.'},
    {eye:'The Shapes',    title:'Six Geometry Families',       desc:'Hexagon, circle, triangle, square, diamond, star — precision-turned and hand-painted in safe water-based colours.'},
    {eye:'Complete',      title:'Ready for Play',              desc:'The finished Sort Master: a symphony of colour, geometry, and tactile joy — ready for thousands of hours of discovery.'}
  ];
  const scEye=document.getElementById('sc-eye');
  const scTitle=document.getElementById('sc-title');
  const scDesc=document.getElementById('sc-desc');
  const dots=document.querySelectorAll('.pdot');
  let step=-1, t=0;
  function loop(setH){
    const h=requestAnimationFrame(()=>loop(setH)); setH(h); t+=.013;
    const rect=sec.getBoundingClientRect();
    const totalH=sec.offsetHeight-window.innerHeight;
    const progress=Math.max(0,Math.min(1,-rect.top/totalH));
    const newStep=Math.min(3,Math.floor(4*progress));
    if(newStep!==step&&STEPS[newStep]){
      step=newStep;
      if(scEye) scEye.textContent=STEPS[newStep].eye;
      if(scTitle) scTitle.textContent=STEPS[newStep].title;
      if(scDesc) scDesc.textContent=STEPS[newStep].desc;
      dots.forEach((d,idx)=>d.classList.toggle('active',idx===newStep));
    }
    const tBase=progress>.04?base.userData.aY:base.userData.sY;
    base.position.y=lerp(base.position.y,tBase,.065);
    baseTop.position.y=lerp(baseTop.position.y,tBase+.3,.065);
    allParts.forEach(p=>{
      const d=p.userData.delay||0;
      const pt=Math.max(0,Math.min(1,(progress-.12-d)/.62));
      const ty=lerp(p.userData.sY,p.userData.aY,easeOut(pt));
      p.position.y=lerp(p.position.y,ty,.052);
      p.rotation.y+=.011;
    });
    group.rotation.x=.05*Math.sin(.1*t)-.08*progress;
    group.rotation.y=.1*Math.sin(.14*t);
    group.position.x=.15*Math.sin(.08*t);
    pL1.intensity=5+.6*Math.sin(.6*t);
    pL2.intensity=2.8+.4*Math.cos(.4*t);
    renderer.render(scene,cam);
  }
  pauseWhenHidden(el, loop);
  window.addEventListener('resize',()=>{
    W=window.innerWidth; H=window.innerHeight;
    renderer.setSize(W,H); cam.aspect=W/H; cam.updateProjectionMatrix();
  });
}

/* ================================================================
   CTA  CANVAS
   ================================================================ */
function initCtaCanvas(){
  const el=document.getElementById('cta-canvas');
  if(!el) return;
  const par=el.parentElement;
  let W=par.clientWidth, H=par.clientHeight||500;
  const renderer=new THREE.WebGLRenderer({canvas:el,antialias:true,alpha:true});
  renderer.setSize(W,H); renderer.setPixelRatio(Math.min(devicePixelRatio,1.5));
  renderer.setClearColor(0,0);
  const scene=new THREE.Scene(), cam=new THREE.PerspectiveCamera(60,W/H,.1,100);
  cam.position.z=14;
  const COLS=[0xFF5A2C,0xFFD025,0x00C49A,0x8B6FE8,0xF53FA5,0x2BB8FF];
  const GEOS=[new THREE.BoxGeometry(.45,.45,.45),new THREE.OctahedronGeometry(.38),
              new THREE.TetrahedronGeometry(.42),new THREE.CylinderGeometry(0,.38,.7,4),
              new THREE.CylinderGeometry(.35,.35,.18,6),new THREE.TorusGeometry(.32,.1,8,20)];
  const COUNT=W<600?12:20;
  const meshes=[];
  for(let i=0;i<COUNT;i++){
    const m=new THREE.Mesh(GEOS[i%GEOS.length],
      new THREE.MeshPhongMaterial({color:COLS[i%6],opacity:.2+.3*Math.random(),transparent:true,shininess:90}));
    m.position.set(28*(Math.random()-.5),18*(Math.random()-.5),10*(Math.random()-.5)-4);
    m.userData={ry:.026*(Math.random()-.5),rx:.018*(Math.random()-.5),
                oy:m.position.y,fs:.4+.5*Math.random(),fo:Math.random()*Math.PI*2};
    scene.add(m); meshes.push(m);
  }
  scene.add(new THREE.AmbientLight(0xffffff,.35));
  const pL=new THREE.PointLight(0xFF5A2C,3.5,36); pL.position.set(0,6,7); scene.add(pL);
  scene.add(Object.assign(new THREE.PointLight(0x8B6FE8,2.8,28),{position:new THREE.Vector3(-10,-5,4)}));
  let t=0;
  function loop(setH){
    const h=requestAnimationFrame(()=>loop(setH)); setH(h); t+=.012;
    meshes.forEach(m=>{
      m.rotation.y+=m.userData.ry; m.rotation.x+=m.userData.rx;
      m.position.y=m.userData.oy+.6*Math.sin(t*m.userData.fs+m.userData.fo);
    });
    pL.position.x=8*Math.cos(.7*t); pL.position.y=6*Math.sin(.5*t);
    renderer.render(scene,cam);
  }
  pauseWhenHidden(el,loop);
  window.addEventListener('resize',()=>{
    W=par.clientWidth; H=par.clientHeight||500;
    renderer.setSize(W,H); cam.aspect=W/H; cam.updateProjectionMatrix();
  });
}

/* ── Init sequence: wait for scripts to load ── */
function init3D(){
  initHeroCanvas();
  initToy1();
  initToy2();
  if('requestIdleCallback' in window){
    requestIdleCallback(initShowcase,{timeout:2000});
    requestIdleCallback(initCtaCanvas,{timeout:2500});
  } else {
    setTimeout(initShowcase,400);
    setTimeout(initCtaCanvas,600);
  }
}

/* Wait for deferred scripts */
window.addEventListener('load',()=>{
  waitForThree(init3D);
  if('requestIdleCallback' in window) {
    requestIdleCallback(initGSAP, {timeout:1500});
  } else {
    setTimeout(initGSAP, 300);
  }
});
